class Boss
{
private:
  float x, y;
  bool active;
  bool bulletActive;
  int life = 400;

public:
  Boss()
  {
    this->x = 500;
    this->y = 550;
    this->active = true;
    this->bulletActive = false;
    printf("Boss created\n");
    printf("x: %f\n", getX());
    printf("y: %f\n", getY());
  }

  void drawSqua(float _x, float _y, float size = 5)
  {
    _x = _x * size + x;
    _y = _y * size + y;
    glBegin(GL_QUADS);
    glVertex2f(_x, _y);
    glVertex2f(_x + size, _y);
    glVertex2f(_x + size, _y + size);
    glVertex2f(_x, _y + size);
    glEnd();
  }

  void drawSquaBullet(float _x, float _y, float size = 5)
  {
    _x = _x * size + x;
    _y = _y * size + y;
    glBegin(GL_QUADS);
    glVertex2f(_x, _y);
    glVertex2f(_x + size, _y);
    glVertex2f(_x + size, _y - size);
    glVertex2f(_x, _y - size);
    glEnd();
  }

  void draw()
  {
    if (active)
    {
      for (int i = 0; i < 71; i++)
      {
        for (int j = 0; j < 62; j++)
        {
          if (vectorBoss[i][j] != 0xffacacac)
          {
            glColor3f(((vectorBoss[i][j] >> 16) & 0xFF) / 255.0f, ((vectorBoss[i][j] >> 8) & 0xFF) / 255.0f, (vectorBoss[i][j] & 0xFF) / 255.0f);
            drawSqua(j, 70 - i);
          }
        }
      }
    }
  }

  void drawBullet()
  {
    if (bulletActive)
    {
      glColor3f(1.0f, 1.0f, 0.0f);
      glBegin(GL_QUADS);
      glVertex2f(x + 140, y);
      glVertex2f(x + 170, y);
      glVertex2f(x + 170, y - 900);
      glVertex2f(x + 140, y - 900);
      glEnd();
    }
  }

  float getX()
  {
    return x;
  }

  float getY()
  {
    return y;
  }

  bool isActive()
  {
    return active;
  }

  void setActive(bool active)
  {
    this->active = active;
  }

  bool checkCollision(int xOffset)
  {
    int defenderInicio = xOffset;   // Posición inicial del defensor
    int defenderFin = xOffset + 81; // Posición final del defensor
    int balaInicio = x + 140;       // Posición inicial de la bala del jefe
    int balaFin = x + 175;          // Posición final de la bala del jefe

    // Verificar si hay colisión entre el defensor y la bala del jefe
    return (balaInicio <= defenderFin && balaFin >= defenderInicio) && bulletActive;
  }

  void decreaseLife()
  {
    life -= 50;
    printf("life %d\n", life);
    if(life <= 0){
      active = false;
    }
  }

  void attack()
  {
    while (active)
    {
      std::this_thread::sleep_for(std::chrono::milliseconds(1000));
      bulletActive = true;
      std::this_thread::sleep_for(std::chrono::milliseconds(1000));
      bulletActive = false;
    }
  }

  void move(float speed)
  {
    while (active)
    {
      x += speed;
      if (x > 1320)
      {
        x = 0;
      }
      std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
  }
};